//-------------------------------------------------------------------------
// function name : f_Addrow
// function desc : LOCATION 수정 및 불량처리 그리드 칼럼 추가
//-------------------------------------------------------------------------
scwin.f_addRow = function () {
  var insertRow = ds_retrieveStockModify.getRowCount();
  if (ds_retrieveStockModify.getRowCount() == 0) {
    // scwin.f_createHeader();
  }
  ds_retrieveStockModify.insertRow();
  ds_retrieveStockModify.setCellData(insertRow, "wrkPlCd", dma_retrieveStockBlock.get("wrkPlCd"));
  ds_retrieveStockModify.setCellData(insertRow, "commCd", dma_retrieveStockBlock.get("commCd"));
  ds_retrieveStockModify.setCellData(insertRow, "stockMgntNo", dma_retrieveStockBlock.get("stockMgntNo"));
  ds_retrieveStockModify.setCellData(insertRow, "stockClntNo", dma_retrieveStockBlock.get("stockClntNo"));
  ds_retrieveStockModify.setCellData(insertRow, "rltNo", dma_retrieveStockBlock.get("rltNo"));
  ds_retrieveStockModify.setCellData(insertRow, "cvsslMgntNo", dma_retrieveStockBlock.get("cvsslMgntNo"));
  ds_retrieveStockModify.setCellData(insertRow, "clntMgntNo", dma_retrieveStockBlock.get("clntMgntNo"));
  ds_retrieveStockModify.setCellData(insertRow, "prodDt", dma_retrieveStockBlock.get("prodDt"));
  ds_retrieveStockModify.setCellData(insertRow, "inStdDt", dma_retrieveStockBlock.get("inStdDt"));
  ds_retrieveStockModify.setCellData(insertRow, "impExpClsCd", dma_retrieveStockBlock.get("impExpClsCd"));
  ds_retrieveStockModify.setCellData(insertRow, "alngvsslStockClsCd", dma_retrieveStockBlock.get("alngvsslStockClsCd"));
  ds_retrieveStockModify.setCellData(insertRow, "stockSts", dma_retrieveStockBlock.get("stockStat"));
  ds_retrieveStockModify.setCellData(insertRow, "normalSts", dma_retrieveStockBlock.get("stockStat"));
  ds_retrieveStockModify.setCellData(insertRow, "badMgntNo", dma_retrieveStockBlock.get("badMgntNo"));
  ds_retrieveStockModify.setCellData(insertRow, "lblock", dma_retrieveStockBlock.get("lblock"));
  ds_retrieveStockModify.setCellData(insertRow, "lbay", dma_retrieveStockBlock.get("lbay"));
  ds_retrieveStockModify.setCellData(insertRow, "lrow", dma_retrieveStockBlock.get("lrow"));
  ds_retrieveStockModify.setCellData(insertRow, "ltier", dma_retrieveStockBlock.get("ltier"));
  ds_retrieveStockModify.setCellData(insertRow, "stockQty", 0);
  ds_retrieveStockModify.setCellData(insertRow, "stockWt", 0);
  ds_retrieveStockModify.setCellData(insertRow, "stockCbm", 0);
  if (dma_retrieveStockBlock.get("badOutbrDt") == "") {
    ds_retrieveStockModify.setCellData(insertRow, "badOutbrDt", scwin.toDay);
  } else {
    ds_retrieveStockModify.setCellData(insertRow, "badOutbrDt", dma_retrieveStockBlock.get("badOutbrDt"));
  }
  var stat = dma_retrieveStockBlock.get("stockStat");
  scwin.f_temmpStat(stat);
  if (dma_retrieveStockBlock.get("commStsCd") != "N1") {
    ds_retrieveStockModify.setCellData(insertRow, "commStsCd", dma_retrieveStockBlock.get("commStsCd"));
  } else {
    ds_retrieveStockModify.setCellData(insertRow, "commStsCd", "");
  }
  ds_retrieveStockModify.setCellData(insertRow, "badRsn", "");
  totalRow.setValue(ds_retrieveStockModify.getRowCount());
  gr_retrieveStockModify.setFocusedCell(insertRow, 12);
};
scwin.f_delRow = function () {
  row = ds_retrieveStockModify.getRowPosition();
  if (ds_retrieveStockModify.getRowStatus(row) == "C") {
    ds_retrieveStockModify.removeRow(row);
    totalRow.setValue(ds_retrieveStockModify.getRowCount());
    return;
  } else {
    // ds_retrieveStockModify.modifyRowStatus(row, "D");
    ds_retrieveStockModify.deleteRow(row);
  }
};
scwin.f_cancel = function () {
  row = ds_retrieveStockModify.getRowPosition();
  if (ds_retrieveStockModify.getRowStatus(row) == "C") {
    ds_retrieveStockModify.removeRow(row);
    totalRow.setValue(ds_retrieveStockModify.getRowCount());
    return;
  } else {
    ds_retrieveStockModify.undoRow(row);
  }
};

