// 수정 버튼 클릭 이벤트
scwin.btn_update_onclick = async function (e) {
  var num_rsltsWt_copy = new Number(8);
  num_rsltsWt_copy = parseFloat(dma_retrieveStockBlockCopy.get("rsltsWt")); // 협정량
  var num_rsltsWt_copyFix = $c.gus.cfInsertComma($p, num_rsltsWt_copy.toFixed(3));
  if (dma_retrieveStockBlockCopy.get("wrkPlCd") == ed_con_wrkPlCd.getValue() && dma_retrieveStockBlockCopy.get("stockClntNo") == ed_stockClntCd.getValue() && dma_retrieveStockBlockCopy.get("commCd") == ed_con_commCd.getValue() && num_rsltsWt_copyFix == ed_rsltsWt.getValue() && dma_retrieveStockBlockCopy.get("inStdDt") == ica_ed_inStdDt.getValue()) {
    scwin.searchFlag = true;
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["재고 기본 정보"]); // "@은(는) 변경된 사항이 없습니다."
    return;
  }
  scwin.searchFlag = false;
  let ret1 = await $c.gus.cfValidate($p, [ed_con_wrkPlCd, ed_con_wrkPlNm, ed_stockClntCd, txt_stockClntNm, ed_con_commCd, ed_con_commNm, ed_rsltsWt, ica_ed_inStdDt]);
  if (!ret1) {
    return;
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_001); // 저장하시겠습니까?
  if (confirm) {
    $c.sbm.execute($p, sbm_update);
  }
};
scwin.sbm_update_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    $c.win.closePopup($p);
  }
};

// LOCATION 수정 및 불량처리 - 저장 버튼 클릭 이벤트
scwin.btn_save_onclick = async function (e) {
  scwin.f_calValue();
  if (!scwin.f_checkMainGrid()) return;
  if (!scwin.f_checkCompare()) return;
  let ret1 = await $c.gus.cfValidate($p, [gr_retrieveStockModify]);
  if (!ret1) {
    return;
  }
  if (!scwin.searchFlag && ds_retrieveStockModify.getModifiedIndex().length <= 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["LOCATION 수정 및 불량처리"]); // 변경된 정보가 없습니다.
    return;
  } else {
    let confirm = await $c.win.confirm($p, MSG_CM_CRM_001); // 저장하시겠습니까?
    if (confirm) {
      scwin.f_commStatInput();
      $c.sbm.execute($p, sbm_save);
    }
  }
};
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    $c.win.closePopup($p);
  }
};

// 재고 Over/Short 관리  - 저장 버튼 클릭 이벤트
scwin.btn_save2_onclick = async function (e) {
  // let ret1 = await $c.gus.cfValidate([gr_retrieveStockOverShortOutbreak]);
  // if (!ret1) {
  //     return;
  // }

  var sumQty1 = 0;
  var sumWt1 = 0;
  var sumCbm1 = 0;
  var sumQty2 = 0;
  var sumWt2 = 0;
  var sumCbm2 = 0;
  for (var i = 0; i < ds_retrieveStockOverShortOutbreak.getRowCount(); i++) {
    var comQty = parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "qty"));
    var comWt = parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "wt"));
    var comCbm = parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "cbm"));
    var gNum = i + 1;
    if ($c.gus.cfIsNull($p, ds_retrieveStockOverShortOutbreak.getCellData(i, "outbrDt"))) {
      $c.win.alert($p, "재고 Over/Short 관리의 " + gNum + "번째 데이터에서 발생일자은(는) 필수 입력 항목입니다.");
      return false;
    }
    if ($c.gus.cfIsNull($p, ds_retrieveStockOverShortOutbreak.getCellData(i, "ovrShortClsCd"))) {
      $c.win.alert($p, "재고 Over/Short 관리의 " + gNum + "번째 데이터에서 Over/Short 구분은(는) 필수 입력 항목입니다.");
      return false;
    }
    if (comQty == 0 && comWt == 0 && comCbm == 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["물량"]); // "@을(를) 입력하십시오."
      //gr_retrieveStockOverShortOutbreak.SetColumn("qty");
      return false;
    }
    if (ds_retrieveStockOverShortOutbreak.getRowStatusValue(i) != 2) {
      // 초기상태:0, 갱신:1, 삽입:2, 삭제:3, 삽입 후 삭제:4
      if (ds_retrieveStockOverShortOutbreak.getCellData(i, "ovrShortClsCd") == "O") {
        sumQty1 = sumQty1 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "qty"));
        sumWt1 = sumWt1 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "wt"));
        sumCbm1 = sumCbm1 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "cbm"));
        sumQty2 = sumQty2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQty"));
        sumWt2 = sumWt2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQWt"));
        sumCbm2 = sumCbm2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldCbm"));
      } else if (ds_retrieveStockOverShortOutbreak.getCellData(i, "ovrShortClsCd") == "S") {
        sumQty1 = sumQty1 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "qty"));
        sumWt1 = sumWt1 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "wt"));
        sumCbm1 = sumCbm1 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "cbm"));
        sumQty2 = sumQty2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQty"));
        sumWt2 = sumWt2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQWt"));
        sumCbm2 = sumCbm2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldCbm"));
      }
    } else {
      if (ds_retrieveStockOverShortOutbreak.getCellData(i, "ovrShortClsCd") == "O") {
        sumQty2 = sumQty2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQty"));
        sumWt2 = sumWt2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQWt"));
        sumCbm2 = sumCbm2 + parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldCbm"));
      } else if (ds_retrieveStockOverShortOutbreak.getCellData(i, "ovrShortClsCd") == "S") {
        sumQty2 = sumQty2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQty"));
        sumWt2 = sumWt2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldQWt"));
        sumCbm2 = sumCbm2 - parseFloat(ds_retrieveStockOverShortOutbreak.getCellData(i, "oldCbm"));
      }
    }
  }
  if (ds_retrieveStockOverShortOutbreak.getModifiedIndex().length <= 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["재고 Over/Short 관리"]); //변경된 정보가 없습니다.
    return;
  } else {
    let confirm = await $c.win.confirm($p, MSG_CM_CRM_001); // 저장하시겠습니까?
    if (confirm) {
      $c.sbm.execute($p, sbm_save1);
    }
  }
};
