// 수량, 중량, CBM 합
scwin.f_calValue = function () {
  for (var i = 0; i < ds_retrieveStockModify.getRowCount(); i++) {
    scwin.sumQty += ds_retrieveStockModify.getCellData(i, "stockQty");
    scwin.sumWt += ds_retrieveStockModify.getCellData(i, "stockWt");
    scwin.sumCbm += ds_retrieveStockModify.getCellData(i, "stockCbm");
  }
};
scwin.f_checkMainGrid = function () {
  var nowMainStatus = dma_retrieveStockBlock.get("stockStat");
  var subGriwRows = ds_retrieveStockModify.getRowCount();
  var highBlock = dma_retrieveStockBlock.get("lblock");
  var highBay = dma_retrieveStockBlock.get("lbay");
  var highRow = dma_retrieveStockBlock.get("lrow");
  var highTier = dma_retrieveStockBlock.get("ltier");
  if (scwin.mainQty < scwin.sumQty) {
    $c.gus.cfAlertMsg($p, ["수정하려는 수량이 총재고수량을 초과하였습니다."]);
    //gr_retrieveStockModify.SetColumn("stockQty"); // 셀을 활성화 시킨다? 포커스 시킨다?
    return false;
  }
  if (scwin.mainWt < scwin.sumWt) {
    $c.gus.cfAlertMsg($p, ["수정하려는 중량이 재고 총중량을 초과하였습니다."]);
    //gr_retrieveStockModify.SetColumn("stockWt");
    return false;
  }
  if (scwin.mainCbm < scwin.sumCbm) {
    $c.gus.cfAlertMsg($p, ["수정하려는 CBM이 총CBM을 초과하였습니다."]);
    //gr_retrieveStockModify.SetColumn("stockCbm");
    return false;
  }
  if (scwin.mainQty == scwin.sumQty && scwin.mainWt == scwin.sumWt && scwin.mainCbm == scwin.sumCbm && nowMainStatus != "N1") {
    dma_retrieveStockBlock.setEmptyValue();
  }
  dma_retrieveStockBlock.set("stockQty", scwin.mainQty - scwin.sumQty);
  dma_retrieveStockBlock.set("stockWt", scwin.mainWt - scwin.sumWt);
  dma_retrieveStockBlock.set("stockCbm", scwin.mainCbm - scwin.sumCbm);
  return true;
};

// 필수입력 체크
scwin.f_checkCompare = function () {
  var row = ds_retrieveStockModify.getRowCount();
  var comBlock = "";
  var comBay = "";
  var comRow = "";
  var comTier = "";
  var comQty = 0;
  var comWt = 0;
  var comCbm = 0;
  var tempStockSts = "";
  var tempBadOutbrDt = "";
  var tempcommStsCd = "";
  var tempBlock = "";
  var tempBay = "";
  var tempRow = "";
  var tempTier = "";
  var highBlock = dma_retrieveStockBlock.get("lblock");
  var highBay = dma_retrieveStockBlock.get("lbay");
  var highRow = dma_retrieveStockBlock.get("lrow");
  var highTier = dma_retrieveStockBlock.get("ltier");
  var highstockStat = dma_retrieveStockBlock.get("stockStat");
  var normalSts = dma_retrieveStockBlock.get("commStsCd");
  for (var i = 0; i < row; i++) {
    var num = i + 1;
    comBlock = ds_retrieveStockModify.getCellData(i, "lblock");
    comBay = ds_retrieveStockModify.getCellData(i, "lbay");
    comRow = ds_retrieveStockModify.getCellData(i, "lrow");
    comTier = ds_retrieveStockModify.getCellData(i, "ltier");
    comStat = ds_retrieveStockModify.getCellData(i, "commStsCd");
    comStockSts = ds_retrieveStockModify.getCellData(i, "stockSts");
    if (comStockSts == "B") {
      if (comStat != "N1") {
        tempBadOutbrDt = ds_retrieveStockModify.getCellData(i, "badOutbrDt");
        tempcommStsCd = ds_retrieveStockModify.getCellData(i, "commStsCd");
        if (tempBadOutbrDt == "") {
          $c.win.alert($p, "[" + num + "]" + " 째 불량발생일자는 필수입니다.");
          //gr_retrieveStockModify.SetColumn("badOutbrDt");
          return false;
        }
        if (tempcommStsCd == "") {
          $c.win.alert($p, "[" + num + "]" + " 째 불량코드는 필수선택입니다.");
          //gr_retrieveStockModify.SetColumn("commStsCd");
          return false;
        }
      }
    }
    if (ds_retrieveStockModify.getCellData(i, "commStsCd") == "") {
      ds_retrieveStockModify.setCellData(i, "commStsCd", "N1");
    }
    if (highstockStat == comStockSts) {
      if (highBlock == comBlock && highBay == comBay && highRow == comRow && highTier == comTier && normalSts == ds_retrieveStockModify.getCellData(i, "commStsCd")) {
        $c.win.alert($p, "[" + num + "]" + " 째 수정사항이 수정전 재고 기본사항과 동일합니다.");
        //gr_retrieveStockModify.SetColumn("lblock");
        return false;
      }
    }
    comQty = parseFloat(ds_retrieveStockModify.getCellData(i, "stockQty"));
    comWt = parseFloat(ds_retrieveStockModify.getCellData(i, "stockWt"));
    comCbm = parseFloat(ds_retrieveStockModify.getCellData(i, "stockCbm"));
    if (comQty == 0 && comWt == 0 && comCbm == 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["물량"]); // "@을(를) 입력하십시오."
      //gr_retrieveStockModify.SetColumn("stockQty");
      return;
    }
    for (var j = i + 1; j <= row; j++) {
      tempBlock = ds_retrieveStockModify.getCellData(j, "lblock");
      tempBay = ds_retrieveStockModify.getCellData(j, "lbay");
      tempRow = ds_retrieveStockModify.getCellData(j, "lrow");
      tempTier = ds_retrieveStockModify.getCellData(j, "ltier");
      tempStsCd = ds_retrieveStockModify.getCellData(j, "commStsCd");
      if (comBlock == tempBlock && comBay == tempBay && comRow == tempRow && comTier == tempTier && comStat == tempStsCd) {
        $c.win.alert($p, "[" + j + "]" + " 째 재고조정 사항이 중복됩니다.");
        //gr_retrieveStockModify.SetColumn("lblock");
        return false;
      }
    }
  }
  return true;
};
scwin.f_commStatInput = function () {
  var row = ds_retrieveStockModify.getRowCount();
  var basicSts = dma_retrieveStockBlock.get("stockStat");
  for (var i = 0; i < row; i++) {
    var subStat = ds_retrieveStockModify.getCellData(i, "stockSts");
    if (basicSts == "N" && subStat == "N") {
      ds_retrieveStockModify.setCellData(i, "commStsCd", "N1");
    } else if (basicSts == "B" && subStat == "N") {
      ds_retrieveStockModify.setCellData(i, "commStsCd", dma_retrieveStockBlock.get("commStsCd"));
      ds_retrieveStockModify.setCellData(i, "badOutbrDt", dma_retrieveStockBlock.get("badOutbrDt"));
    }
  }
};

