scwin.f_temmpStat = function (temmpStat) {
  if (temmpStat == "B") {
    gr_retrieveStockModify.setHeaderStyle("column139", "color", "red");
    gr_retrieveStockModify.setHeaderStyle("column137", "color", "red");
    gr_retrieveStockModify.setHeaderStyle("column135", "color", "blue");
    gr_retrieveStockModify.setColumnReadOnly('badOutbrDt', false);
    gr_retrieveStockModify.setColumnReadOnly('commStsCd', false);
    gr_retrieveStockModify.setColumnReadOnly('badRsn', false);
    if (dma_retrieveStockBlock.get("badOutbrDt") == "") {
      ds_retrieveStockModify.setCellData(ds_retrieveStockModify.getRowPosition(), "badOutbrDt", scwin.toDay);
    } else {
      ds_retrieveStockModify.setCellData(ds_retrieveStockModify.getRowPosition(), "badOutbrDt", dma_retrieveStockBlock.get("badOutbrDt"));
    }
  } else if (temmpStat == "N") {
    gr_retrieveStockModify.setHeader;
    gr_retrieveStockModify.setHeaderStyle("column139", "color", "black");
    gr_retrieveStockModify.setHeaderStyle("column137", "color", "black");
    gr_retrieveStockModify.setHeaderStyle("column135", "color", "black");
    gr_retrieveStockModify.setColumnReadOnly('badOutbrDt', true);
    gr_retrieveStockModify.setColumnReadOnly('commStsCd', true);
    gr_retrieveStockModify.setColumnReadOnly('badRsn', true);
    ds_retrieveStockModify.setCellData(ds_retrieveStockModify.getRowPosition(), "badOutbrDt", "");
  }
};

