// G A U C E   C O M P O N E N T' S   E V E N T S  
// Grid 컬럼 이동시 이벤트
//-------------------------------------------------------------------------
scwin.gr_retrieveStockModify_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
  let Colid = gr_retrieveStockModify.getColumnID(columnIndex);
  switch (Colid) {
    case "commStsCd":
      //gr_retrieveStockModify.UrlImages+="<I>Type='PopupBotton', Url='/common/images/search.gif', Fit='AutoFit', Flat='True'</I>";
      break;
    case "badOutbrDt":
      //gr_retrieveStockModify.UrlImages+="<I>Type='PopupBotton', Url='/common/images/calendar.gif', Fit='AutoFit', Flat='True'</I>";
      break;
    default:
      break;
  }
  var v_wrkPlCd = ds_retrieveStockModify.getCellData(rowIndex, "wrkPlCd");
  var v_blck = ds_retrieveStockModify.getCellData(rowIndex, "lblock");
  var v_bay = ds_retrieveStockModify.getCellData(rowIndex, "lbay");
  var v_rw = ds_retrieveStockModify.getCellData(rowIndex, "lrow");
  var v_tier = ds_retrieveStockModify.getCellData(rowIndex, "ltier");
  if (Colid == "lblock" && v_wrkPlCd != "") {
    scwin.f_retrieveBlckInfo(v_wrkPlCd);
  } else if (Colid == "lbay" && v_wrkPlCd != "" && v_blck != "") {
    scwin.f_retrieveBayInfo(v_wrkPlCd, v_blck);
  } else if (Colid == "lrow" && v_wrkPlCd != "" && v_blck != "" && v_bay != "") {
    scwin.f_retrieveRwInfo(v_wrkPlCd, v_blck, v_bay);
  } else if (Colid == "ltier" && v_wrkPlCd != "" && v_blck != "" && v_bay != "" && v_rw != "") {
    scwin.f_retrieveTierInfo(v_wrkPlCd, v_blck, v_bay, v_rw);
  }
};
scwin.gr_retrieveStockModify_onrowindexchange = function (rowIndex, oldRow) {
  // 재고상태에 따라 활성/비활성
  var temmpStat = ds_retrieveStockModify.getCellData(rowIndex, "stockSts"); // 재고상태
  scwin.f_temmpStat(temmpStat);
};
scwin.gr_retrieveStockModify_onbeforeedit = function (rowIndex, columnIndex, value) {
  scwin.olddata = value;
};
scwin.gr_retrieveStockModify_onafteredit = function (rowIndex, columnIndex, value) {
  let colid = gr_retrieveStockModify.getColumnID(columnIndex);
  for (var i = 0; i < ds_retrieveStockModify.getRowCount(); i++) {
    if ($c.gus.cfIsNull($p, ds_retrieveStockModify.getCellData(i, "stockQty"))) {
      ds_retrieveStockModify.setCellData(i, "stockQty", 0.000);
    }
    if ($c.gus.cfIsNull($p, ds_retrieveStockModify.getCellData(i, "stockWt"))) {
      ds_retrieveStockModify.setCellData(i, "stockWt", 0.000);
    }
    if ($c.gus.cfIsNull($p, ds_retrieveStockModify.getCellData(i, "stockCbm"))) {
      ds_retrieveStockModify.setCellData(i, "stockCbm", 0.000);
    }
  }
  if (colid == "stockSts") {
    var temmpStat = ds_retrieveStockModify.getCellData(rowIndex, "stockSts"); // 재고상태
    scwin.f_temmpStat(temmpStat);
  }
  if (colid == "stockWt") {
    if (ds_retrieveStockModify.getCellData(rowIndex, "stockWt") < 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["수정중량"]);
      ds_retrieveStockModify.setCellData(rowIndex, "stockWt", 0.000);
      return false;
    }
  }
  if (colid == "stockCbm") {
    if (ds_retrieveStockModify.getCellData(rowIndex, "stockCbm") < 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["수정CBM"]);
      ds_retrieveStockModify.setCellData(rowIndex, "stockCbm", 0.000);
      return false;
    }
  }
};
scwin.gr_retrieveStockOverShortOutbreak_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
  if (ds_retrieveStockOverShortOutbreak.getRowStatus(rowIndex) == "C") {
    //클릭한 row가 insert 일 경우
    gr_retrieveStockOverShortOutbreak.setColumnReadOnly('outbrDt', false);
    gr_retrieveStockOverShortOutbreak.setColumnReadOnly('ovrShortClsCd', false);
  } else {
    //클릭한 row가 insert가 아닐 경우
    gr_retrieveStockOverShortOutbreak.setColumnReadOnly('outbrDt', true);
    gr_retrieveStockOverShortOutbreak.setColumnReadOnly('ovrShortClsCd', true);
  }
};
scwin.gr_retrieveStockOverShortOutbreak_onbeforeedit = function (rowIndex, columnIndex, value) {
  let colid = gr_retrieveStockModify.getColumnID(columnIndex);
  var v_wrkPlCd = ds_retrieveStockModify.getCellData(rowIndex, "wrkPlCd");
  var v_blck = ds_retrieveStockModify.getCellData(rowIndex, "lblock");
  var v_bay = ds_retrieveStockModify.getCellData(rowIndex, "lbay");
  var v_rw = ds_retrieveStockModify.getCellData(rowIndex, "lrow");
  var v_tier = ds_retrieveStockModify.getCellData(rowIndex, "ltier");
  if (colid == "lblock" && v_wrkPlCd != "") {
    scwin.f_retrieveBlckInfo(v_wrkPlCd);
  } else if (colid == "lbay" && v_wrkPlCd != "" && v_blck != "") {
    scwin.f_retrieveBayInfo(v_wrkPlCd, v_blck);
  } else if (colid == "lrow" && v_wrkPlCd != "" && v_blck != "" && v_bay != "") {
    scwin.f_retrieveRwInfo(v_wrkPlCd, v_blck, v_bay);
  } else if (colid == "ltier" && v_wrkPlCd != "" && v_blck != "" && v_bay != "" && v_rw != "") {
    scwin.f_retrieveTierInfo(v_wrkPlCd, v_blck, v_bay, v_rw);
  }
};
scwin.gr_retrieveStockOverShortOutbreak_oneditend = function (rowIndex, columnIndex, value) {};
scwin.gr_retrieveStockOverShortOutbreak_onafteredit = function (rowIndex, columnIndex, value) {
  let colid = gr_retrieveStockOverShortOutbreak.getColumnID(columnIndex);
  for (var i = 0; i < ds_retrieveStockOverShortOutbreak.getRowCount(); i++) {
    if ($c.gus.cfIsNull($p, ds_retrieveStockOverShortOutbreak.getCellData(i, "qty"))) {
      ds_retrieveStockOverShortOutbreak.setCellData(i, "qty", 0);
    }
    if ($c.gus.cfIsNull($p, ds_retrieveStockOverShortOutbreak.getCellData(i, "wt"))) {
      ds_retrieveStockOverShortOutbreak.setCellData(i, "wt", 0.000);
    }
    if ($c.gus.cfIsNull($p, ds_retrieveStockOverShortOutbreak.getCellData(i, "cbm"))) {
      ds_retrieveStockOverShortOutbreak.setCellData(i, "cbm", 0.000);
    }
  }
  if (colid == "wt") {
    if (ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "qty") < 0) {
      if (ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "wt") == ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "qty") * (dma_retrieveStockBlock.get("stockWt") / dma_retrieveStockBlock.get("stockQty"))) {
        ds_retrieveStockOverShortOutbreak.setCellData(rowIndex, "wt", ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "qty") * (dma_retrieveStockBlock.get("stockWt") / dma_retrieveStockBlock.get("stockQty")));
        return false;
      }
    }
    if (ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "wt") < 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["중량"]);
      ds_retrieveStockOverShortOutbreak.setCellData(rowIndex, "wt", 0.000);
      return false;
    }
  }
  if (colid == "cbm") {
    if (ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "cbm") < 0) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["수정CBM"]);
      ds_retrieveStockOverShortOutbreak.setCellData(rowIndex, "cbm", 0.000);
      return false;
    }
  }
  if (colid == "qty") {
    if (dma_retrieveStockBlock.get("stockQty") != "0") {
      ds_retrieveStockOverShortOutbreak.setCellData(rowIndex, "wt", ds_retrieveStockOverShortOutbreak.getCellData(rowIndex, "qty") * (dma_retrieveStockBlock.get("stockWt") / dma_retrieveStockBlock.get("stockQty")));
    }
  }
};

